Hey, I'm working on a custom storage engine for a database project and I need to implement the core logic for an LSM-Tree. I've got the basic structure for the MemTable and the SSTable interface, but I'm struggling with the transition between them. 

Can you implement the `LSMTree` class so it handles `put`, `get`, and `delete` correctly? Also, once the `MemTable` reaches a certain size, it should flush to an `SSTable`.

Here is the skeleton and the test suite I'm using to verify my implementation. If it passes these, I'm good to go.

```python
import abc

class SSTable(abc.ABC):
    @abc.abstractmethod
    def write(self, data: dict):
        pass

    @abc.abstractmethod
    def read(self, key: str):
        pass

class DiskSSTable(SSTable):
    """Placeholder for actual disk I/O logic."""
    def __init__(self, filename):
        self.filename = filename
        self.data = {}

    def write(self, data: dict):
        # Real implementation would write to disk
        self.data.update(data)

    def read(self, key: str):
        # Real implementation would read from disk
        return self.data.get(key)

class LSMTree:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.memtable = {}
        self.sstables = []

    def put(self, key: str, value: str):
        pass

    def get(self, key: str):
        pass

    def delete(self, key: str):
        pass

    def _flush(self):
        pass

# --- TEST SUITE ---
def test_lsm_tree():
    lsm = LSMTree(capacity=3)

    # Test basic put and get
    lsm.put("a", "1")
    assert lsm.get("a") == "1", "Failed basic put/get"

    # Test capacity/flush trigger
    lsm.put("b", "2")
    lsm.put("c", "3") # This should trigger a flush if capacity is 3

    # Check if memtable is cleared after flush
    assert len(lsm.memtable) == 0, "Memtable was not cleared after flush"
    assert len(lsm.sstables) > 0, "No SSTables created after flush"

    # Test get from SSTable
    assert lsm.get("b") == "2", "Failed to get value from SSTable"

    # Test delete
    lsm.delete("a")
    assert lsm.get("a") is None, "Delete failed"

    # Test overwriting
    lsm.put("b", "99")
    assert lsm.get("b") == "99", "Failed to overwrite value"

    print("All tests passed!")

if __name__ == "__main__":
    test_lsm_tree()
```

